package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.io.InputStreamReader;
import java.nio.charset.Charset;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedConstruction;
import org.mockito.Mockito;

class CSVParserParseTest {

    private File mockFile;
    private Charset charset;
    private CSVFormat mockFormat;

    @BeforeEach
    void setup() {
        mockFile = mock(File.class);
        charset = Charset.defaultCharset();
        mockFormat = mock(CSVFormat.class);
    }

    @Test
    void parse_NullFile_ThrowsNullPointerException() {
        NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
            CSVParser.parse((File) null, charset, mockFormat);
        });
        assertEquals("file", thrown.getMessage());
    }

    @Test
    void parse_NullFormat_ThrowsNullPointerException() {
        NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
            CSVParser.parse(mockFile, charset, null);
        });
        assertEquals("format", thrown.getMessage());
    }

    @Test
    void parse_ValidFile_ReturnsCSVParser() throws Exception {
        try (MockedConstruction<FileInputStream> fisMock = Mockito.mockConstruction(FileInputStream.class);
             MockedConstruction<InputStreamReader> isrMock = Mockito.mockConstruction(InputStreamReader.class)) {

            // We do not need to mock FileInputStream or InputStreamReader internals for this test,
            // just ensure constructor calls succeed.

            CSVParser parser = CSVParser.parse(mockFile, charset, mockFormat);

            assertNotNull(parser);
            // Using reflection to verify internal fields since CSVParser constructor and fields are package-private or private
            var formatField = CSVParser.class.getDeclaredField("format");
            formatField.setAccessible(true);
            assertSame(mockFormat, formatField.get(parser));
        }
    }
}
